var numberOfSubstrings = function(s) {
    let a = 0;
    let b = 0;
    let c = 0;
    let left = 0;
    let res = 0;

    for (let i = 0; i < s.length; i++) {
        switch (s[i]) {
            case 'a': a++; break;
            case 'b': b++; break;
            case 'c': c++; break;
        }

        while (a && b && c) {
            res += s.length - i;

            switch (s[left]) {
                case 'a': a--; break;
                case 'b': b--; break;
                case 'c': c--; break;
            }
            left++;
        }
    }

    return res;
};
